        let repo = PathBuf::from("/tmp/exec-merge-no-worktree");
        let branch = "feature/no-worktree".to_string();

        let mut app = App::with_config_and_worktree_service(
            Config::default(),
            Arc::new(StubBackend),
            Arc::new(EmptyListMock),
            Box::new(InMemoryConfigProvider::new()),
        );

